import { Question } from "@/context/AppContext";

let idCounter = 2000;
function makeQ(
  title: string,
  category: string,
  difficulty: "Easy" | "Medium" | "Hard",
  answer: string,
  notes: string = ""
): Question {
  idCounter++;
  return {
    id: `bank-${idCounter}`,
    title,
    category,
    difficulty,
    answer,
    notes,
    status: "Not Started",
    createdAt: new Date().toISOString(),
  };
}

export const QUESTION_BANK_EXPANDED: Question[] = [

  // ═══════════════════════════════════════════════════════════════
  // EMBEDDED C/C++ — EXPANDED (80 more)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What happens if you dereference a NULL pointer in embedded C?", "Embedded C/C++", "Easy",
    "Dereferencing NULL causes undefined behavior. On systems with an MMU/MPU, it triggers a fault (HardFault on ARM Cortex-M with MPU enabled). On bare-metal without memory protection, it reads/writes address 0x00000000 — which may be the vector table on ARM, causing silent corruption. Always check pointers before dereferencing."),
  makeQ("What is the difference between pre-increment (++i) and post-increment (i++) in C?", "Embedded C/C++", "Easy",
    "Pre-increment (++i) increments the value then returns the new value. Post-increment (i++) returns the current value then increments. In performance-critical embedded code, pre-increment can be slightly more efficient as it doesn't need a temporary copy, though modern compilers usually optimize both equally."),
  makeQ("What is a reentrant function and why is it important in embedded systems?", "Embedded C/C++", "Medium",
    "A reentrant function can be safely called simultaneously from multiple execution contexts (main code + ISRs, or multiple RTOS tasks). It uses only local variables or properly protected shared data — no static/global variables without synchronization. Important because ISRs can interrupt any function at any time."),
  makeQ("Explain the difference between memcpy() and memmove() in C.", "Embedded C/C++", "Medium",
    "memcpy() copies n bytes from source to destination but behavior is undefined if regions overlap. memmove() handles overlapping regions safely by copying through a temporary buffer or copying in the correct direction. Use memmove() when source and destination might overlap; memcpy() when they definitely don't (it's faster)."),
  makeQ("What is the 'extern' keyword used for in C?", "Embedded C/C++", "Easy",
    "extern declares a variable or function that is defined in another translation unit (source file). It tells the compiler 'this exists somewhere else — don't allocate storage here.' Used in header files to share global variables across files. Without extern, each file would create its own copy."),
  makeQ("How do you implement a state machine in C?", "Embedded C/C++", "Medium",
    "Common approaches: 1) Switch-case: switch on current state, handle events in each case. 2) Table-driven: array of function pointers indexed by state and event — more scalable. 3) State pattern (C++): each state is an object with virtual methods. For embedded, switch-case is most common for small machines; table-driven for complex ones.",
    "Be ready to code a simple state machine on the whiteboard."),
  makeQ("What is the sizeof operator and how does it work with arrays and pointers?", "Embedded C/C++", "Medium",
    "sizeof returns the byte size of a type or object at compile time. For arrays: sizeof(arr) returns total array size. For pointers: sizeof(ptr) returns pointer size (4 bytes on 32-bit). When an array is passed to a function, it decays to a pointer, so sizeof inside the function gives pointer size, not array size. This is a common source of bugs."),
  makeQ("What is the comma operator in C?", "Embedded C/C++", "Easy",
    "The comma operator evaluates both operands and returns the value of the right operand. Example: x = (a++, b++) sets x to the original value of b. It's sometimes used in for-loop expressions or macros. In embedded, it's relatively rare and can reduce readability."),
  makeQ("What are variadic functions in C and how do they work?", "Embedded C/C++", "Hard",
    "Variadic functions accept a variable number of arguments (e.g., printf). Implemented using <stdarg.h>: va_list, va_start, va_arg, va_end macros. The compiler doesn't type-check variadic arguments. In embedded, custom printf-like debug functions are common. Variadic functions use the stack to pass extra arguments."),
  makeQ("Explain the difference between 'break' and 'continue' in a loop.", "Embedded C/C++", "Easy",
    "break immediately exits the innermost loop entirely. continue skips the rest of the current iteration and jumps to the next iteration's condition check. In embedded polling loops, break is used when a condition is met; continue is used to skip processing for irrelevant events."),
  makeQ("What is the 'register' keyword in C?", "Embedded C/C++", "Easy",
    "The register keyword suggests the compiler store a variable in a CPU register for faster access. Modern compilers largely ignore this hint and optimize register allocation themselves. You cannot take the address of a register variable (&var is illegal). It's rarely used in modern code."),
  makeQ("What are the rules for implicit type conversions (integer promotions) in C?", "Embedded C/C++", "Medium",
    "Types smaller than int (char, short) are promoted to int in expressions. If operands have different types, the lower-rank type is converted to the higher-rank type. Signed/unsigned mixing: if the unsigned type is >= rank of signed, the signed is converted to unsigned — this can cause bugs with negative values appearing as large positive numbers."),
  makeQ("What is a callback function in embedded C?", "Embedded C/C++", "Medium",
    "A callback is a function passed as a pointer to another function, which calls it later. Used in embedded for: interrupt handlers registered at runtime, event-driven architectures, driver APIs (register a callback for data-ready events), and timer expiry handlers. Enables decoupling and modularity."),
  makeQ("How do you write portable embedded C code?", "Embedded C/C++", "Hard",
    "Use stdint.h types (uint32_t instead of int), avoid compiler-specific extensions or isolate them behind macros, use #pragma once or include guards, abstract hardware access behind HAL functions, avoid endianness assumptions, use sizeof instead of hard-coded sizes, and document/test on multiple targets. Follow MISRA C guidelines for safety-critical code."),
  makeQ("What is the difference between '==' and '=' in C? Why is this relevant in embedded?", "Embedded C/C++", "Easy",
    "= is assignment, == is comparison. A common bug: if (x = 5) assigns 5 to x and always evaluates true. This is especially dangerous in embedded where it can enable unintended hardware actions. Defense: write constants on the left: if (5 == x) — a typo if (5 = x) causes a compile error. Many coding standards enforce this."),
  makeQ("What is the scope of a variable declared inside a for loop in C99/C11?", "Embedded C/C++", "Easy",
    "In C99 and later, a variable declared in the for loop initializer (for(int i=0;...)) has scope limited to the loop body. In C89/C90, this syntax is not allowed — the variable must be declared before the loop. Most modern embedded compilers support C99+, but some legacy codebases still use C89."),
  makeQ("What is a compound literal in C99?", "Embedded C/C++", "Medium",
    "A compound literal creates an unnamed object of a specified type: (type){initializer}. Example: pass a struct to a function without declaring a variable: func((struct Point){.x=1, .y=2}). Useful in embedded for one-off configuration structs, DMA transfer descriptors, or register initialization values."),
  makeQ("How do you safely cast between different pointer types in embedded C?", "Embedded C/C++", "Hard",
    "Use explicit casts and ensure proper alignment. Casting between unrelated types (type punning) is technically undefined behavior in strict C, though common in embedded. Safer alternatives: use unions for type punning, memcpy for copying between types, or compile with -fno-strict-aliasing. Always consider alignment requirements — unaligned access faults on some ARM modes."),
  makeQ("What are MISRA C rules and why are they important?", "Embedded C/C++", "Medium",
    "MISRA C is a set of coding guidelines for safety-critical C code, developed for the automotive industry but widely used in embedded. Key rules include: no dynamic memory allocation, no recursion, limited pointer arithmetic, mandatory braces, no implicit type conversions, and restricted use of certain C features. Enforced by static analysis tools like PC-lint, Polyspace, and LDRA."),
  makeQ("What is the difference between a shallow copy and a deep copy of a struct?", "Embedded C/C++", "Medium",
    "A shallow copy (struct assignment: a = b) copies all bytes of the struct, including pointer values. Both copies then point to the same memory. A deep copy also duplicates any dynamically allocated memory the struct's pointers reference. In embedded, structs rarely use dynamic allocation, so shallow copies are usually sufficient and safe."),
  makeQ("What does the 'const' keyword mean when applied to a pointer? Explain all variations.", "Embedded C/C++", "Medium",
    "const int *p: pointer to const int — can't modify the value through p. int *const p: const pointer — can't change where p points. const int *const p: const pointer to const int — neither can change. In embedded, 'pointer to const' is used for read-only hardware registers and function parameters that shouldn't be modified."),
  makeQ("What is a lookup table and when is it used in embedded systems?", "Embedded C/C++", "Medium",
    "A lookup table (LUT) stores pre-computed values in an array, replacing expensive runtime calculations with a simple array access. Used for: sine/cosine tables in DSP, CRC computation, gamma correction, sensor linearization, and character encoding. Trade-off: uses Flash/ROM memory but saves CPU time. Put in const/Flash to avoid using RAM."),
  makeQ("What is the assert() macro and should you use it in embedded code?", "Embedded C/C++", "Medium",
    "assert() checks a condition and aborts if false, printing an error. In embedded, the standard assert may not work (no stdout). Alternatives: custom assert that triggers a breakpoint, logs to UART, or sets an error LED. Use during development for catching impossible conditions. Disable in production builds (NDEBUG) to save code space. Some safety standards require defensive checks to remain."),
  makeQ("How do you implement fixed-point arithmetic in C?", "Embedded C/C++", "Hard",
    "Use integers with an implicit scaling factor. For Q16.16 format: multiply by 65536 to convert from float. Addition/subtraction works normally. Multiplication: result = (int64_t)a * b >> 16. Division: result = ((int64_t)a << 16) / b. Advantages: works on MCUs without FPU, deterministic timing. Must handle overflow carefully."),
  makeQ("What is the difference between a while loop and a do-while loop?", "Embedded C/C++", "Easy",
    "while checks the condition before executing the body (may never execute). do-while executes the body first, then checks the condition (always executes at least once). In embedded, do-while is commonly used in macros: #define MACRO do { ... } while(0) — this makes the macro behave like a single statement in all contexts."),
  makeQ("What are GCC attributes commonly used in embedded C?", "Embedded C/C++", "Hard",
    "__attribute__((packed)): no padding in struct. __attribute__((aligned(n))): force alignment. __attribute__((section(\"name\"))): place variable in specific memory section. __attribute__((weak)): allow override by another definition. __attribute__((noreturn)): function never returns. __attribute__((used)): prevent linker from removing unused symbol. __attribute__((interrupt)): mark as ISR."),
  makeQ("What is a jump table and how is it implemented?", "Embedded C/C++", "Medium",
    "A jump table is an array of function pointers used to dispatch function calls based on an index. Example: void (*handlers[])(void) = {handler0, handler1, handler2}; handlers[index](); Faster than switch-case for large numbers of cases. Used in: command parsers, protocol handlers, state machines, and interrupt vector tables."),
  makeQ("Explain the storage classes in C: auto, register, static, extern.", "Embedded C/C++", "Easy",
    "auto: default for local variables, allocated on stack, scope limited to block. register: suggests register storage, rarely used now. static: preserves value between calls (local) or limits scope to file (global/function). extern: declares variable/function defined elsewhere. In embedded, static is most important for encapsulating module-private data."),
  makeQ("What is tail call optimization and does it matter in embedded?", "Embedded C/C++", "Hard",
    "Tail call optimization (TCO) reuses the current stack frame when the last action of a function is calling another function. This prevents stack growth in recursive calls. In embedded with limited stack space, TCO is important but not guaranteed by all compilers. GCC may do it at -O2 or higher. For safety, avoid recursion in embedded — use iteration instead."),
  makeQ("What is the volatile sig_atomic_t type?", "Embedded C/C++", "Medium",
    "sig_atomic_t is an integer type guaranteed to be accessed atomically with respect to signals (interrupts in embedded context). volatile sig_atomic_t is the proper way to declare flags shared between ISRs and the main loop in portable C. However, in practice on 32-bit ARM, any 32-bit aligned variable is atomically accessed, so this is more important for portability."),

  // ═══════════════════════════════════════════════════════════════
  // RTOS & SCHEDULING — EXPANDED (50 more)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What is a memory pool in an RTOS and when would you use one?", "RTOS & Scheduling", "Medium",
    "A memory pool is a pre-allocated set of fixed-size blocks. Tasks can allocate/free blocks in O(1) deterministic time with no fragmentation. Used instead of malloc/free for: message buffers, protocol packets, sensor data structures. RTOS APIs: osMemoryPoolAlloc/Free (CMSIS-RTOS2), xQueueCreate with static allocation (FreeRTOS)."),
  makeQ("What is the difference between a counting semaphore and a binary semaphore?", "RTOS & Scheduling", "Easy",
    "Binary semaphore has a count of 0 or 1 — used for signaling events. Counting semaphore has a count from 0 to N — used for managing a pool of N resources (e.g., 5 UART channels, 3 DMA streams). Take decrements the count (blocks at 0); Give increments (up to max)."),
  makeQ("How does priority inheritance work in a mutex?", "RTOS & Scheduling", "Hard",
    "When a high-priority task blocks on a mutex held by a low-priority task, the RTOS temporarily raises the low-priority task's priority to match the blocked task's priority. This prevents medium-priority tasks from preempting and extending the blocking time. When the mutex is released, the priority reverts. This mitigates priority inversion but adds RTOS overhead."),
  makeQ("What is a timer callback in FreeRTOS?", "RTOS & Scheduling", "Easy",
    "A software timer in FreeRTOS executes a callback function after a specified period. The callback runs in the timer service task (daemon) context, not in an ISR. Timers can be one-shot or auto-reload (periodic). They're useful for: timeouts, periodic polling, debouncing, and delayed actions without creating dedicated tasks."),
  makeQ("What is thread-safety and how do you achieve it?", "RTOS & Scheduling", "Medium",
    "Thread-safe code can be executed by multiple tasks simultaneously without corruption. Techniques: mutexes for shared data access, atomic operations for simple flags/counters, message queues for inter-task data transfer (no shared memory), reentrant functions (only use local variables), and disabling interrupts for very short critical sections."),
  makeQ("What is the producer-consumer problem?", "RTOS & Scheduling", "Medium",
    "A classic synchronization problem: producers generate data and put it in a shared buffer; consumers take data out. Challenges: buffer full (producer must wait), buffer empty (consumer must wait), concurrent access (corruption). Solution in RTOS: use a message queue — it handles synchronization, blocking, and buffering automatically."),
  makeQ("How do you detect stack overflow in an RTOS?", "RTOS & Scheduling", "Medium",
    "Methods: 1) Stack canary — place a known pattern at the end of the stack; check if it's overwritten. 2) FreeRTOS configCHECK_FOR_STACK_OVERFLOW uses hooks. 3) MPU — configure a no-access region at the stack boundary (triggers fault on overflow). 4) Monitor high-water mark (uxTaskGetStackHighWaterMark). Always size stacks generously during development."),
  makeQ("What is the difference between xQueueSend and xQueueSendFromISR in FreeRTOS?", "RTOS & Scheduling", "Medium",
    "xQueueSend can block the calling task if the queue is full — must NOT be used from an ISR (ISRs can't block). xQueueSendFromISR is the interrupt-safe version — it never blocks; if the queue is full, it returns an error. It also takes a pxHigherPriorityTaskWoken parameter for yielding to a higher-priority task after the ISR."),
  makeQ("What is a task notification in FreeRTOS?", "RTOS & Scheduling", "Medium",
    "Task notifications are a lightweight alternative to semaphores/queues for simple signaling. Each task has a built-in 32-bit notification value. Functions: xTaskNotifyGive/ulTaskNotifyTake (binary/counting semaphore replacement), xTaskNotify/xTaskNotifyWait (general-purpose). Faster and uses less RAM than semaphores. Limitation: only one sender-to-one-receiver."),
  makeQ("What is rate monotonic analysis?", "RTOS & Scheduling", "Hard",
    "Rate Monotonic Analysis (RMA) mathematically verifies if a set of periodic tasks can meet all their deadlines under fixed-priority preemptive scheduling. Each task has a period and worst-case execution time. The utilization bound test: sum(Ci/Ti) ≤ n(2^(1/n) - 1) guarantees schedulability. For exact analysis, use response time analysis: Ri = Ci + Σ ceil(Ri/Tj)*Cj."),
  makeQ("What is Earliest Deadline First (EDF) scheduling?", "RTOS & Scheduling", "Hard",
    "EDF is a dynamic-priority algorithm where the task with the closest deadline runs first. It's optimal for single-processor systems — can achieve 100% CPU utilization (vs ~69% for RMS). However, it's more complex to implement, harder to analyze under overload, and less common in commercial RTOS. Used in some real-time research and multimedia systems."),
  makeQ("What is a critical section and how do you protect it?", "RTOS & Scheduling", "Easy",
    "A critical section is code that accesses shared resources and must not be interrupted/preempted. Protection methods: 1) Disable interrupts (fastest, for very short sections). 2) Disable scheduler (prevents task switch but allows ISRs). 3) Mutex (allows other tasks to run, best for longer sections). Choose based on section length and real-time requirements."),
  makeQ("What is jitter in real-time systems?", "RTOS & Scheduling", "Medium",
    "Jitter is the variation in timing of a periodic event. For a task supposed to run every 10ms, if actual intervals vary from 9.5ms to 10.5ms, the jitter is 1ms. Causes: interrupt latency variations, higher-priority task preemption, cache misses. Critical in: motor control (torque ripple), audio (clicks/pops), communication (bit timing errors). Minimize by using hardware timers and high-priority tasks."),
  makeQ("What is the difference between a hard deadline and a firm deadline?", "RTOS & Scheduling", "Medium",
    "Hard deadline: missing it causes system failure (safety hazard). Firm deadline: missing it makes the result worthless (but not dangerous) — e.g., a dropped video frame. Soft deadline: missing it degrades quality gradually. This classification determines the scheduling approach and safety certification requirements."),
  makeQ("How do you measure worst-case execution time (WCET)?", "RTOS & Scheduling", "Hard",
    "Methods: 1) Static analysis — tools analyze code paths without running it (AbsInt aiT). Most conservative. 2) Measurement-based — run code with GPIO toggling and oscilloscope/logic analyzer. Must cover worst-case inputs. 3) Hybrid — combine static analysis with measurements. WCET must account for: cache misses, pipeline stalls, wait states, and interrupt interference."),
  makeQ("What is the difference between Task and Thread in embedded RTOS terminology?", "RTOS & Scheduling", "Easy",
    "In most RTOS contexts, Task and Thread are used interchangeably — both refer to an independent execution context with its own stack, priority, and state. FreeRTOS uses 'task,' CMSIS-RTOS uses 'thread,' Zephyr uses 'thread.' In Linux, threads share a process address space, but this distinction doesn't apply in flat-memory RTOS."),
  makeQ("How does FreeRTOS heap management work? Describe heap_1 through heap_5.", "RTOS & Scheduling", "Hard",
    "heap_1: allocate only, never free. Simplest, deterministic. heap_2: allows free, but no coalescing (fragments). heap_3: wraps standard malloc/free with thread safety. heap_4: first-fit with coalescing — good general purpose. heap_5: like heap_4 but supports non-contiguous memory regions. Choose based on your allocation pattern and memory layout."),
  makeQ("What is a mailbox in an RTOS?", "RTOS & Scheduling", "Easy",
    "A mailbox (in some RTOS like µC/OS) is a message queue that holds a single message (typically a pointer). Tasks can pend (wait) on the mailbox. When a message is posted, the highest-priority waiting task is unblocked. It's essentially a 1-element queue. Some RTOS use 'mailbox' and 'queue' interchangeably."),
  makeQ("What is time-slicing in an RTOS?", "RTOS & Scheduling", "Easy",
    "Time-slicing gives each ready task of equal priority a fixed time quantum (slice) of CPU time before preempting it for the next same-priority task. Also called round-robin among equal priorities. Configured with configTICK_RATE_HZ in FreeRTOS. Useful when multiple tasks at the same priority need fair CPU access."),
  makeQ("How do you share data between an ISR and a task safely?", "RTOS & Scheduling", "Medium",
    "Options: 1) Volatile flag — ISR sets flag, task reads and clears it (simple, for single values). 2) Queue (xQueueSendFromISR) — ISR posts data, task reads from queue (safest for structured data). 3) Stream/message buffer — for byte streams. 4) Task notification — ISR notifies task to wake up. Never use mutexes in ISRs (they block). Keep ISR processing minimal."),
  makeQ("What is a deferred interrupt processing pattern?", "RTOS & Scheduling", "Medium",
    "Instead of doing all work in the ISR, you do minimal work (read status, clear interrupt, grab data) and defer the heavy processing to a task. The ISR signals the task via semaphore, queue, or task notification. The task runs at an appropriate priority and does the complex processing. This keeps ISR execution time short and deterministic."),
  makeQ("What is a resource ceiling in Priority Ceiling Protocol?", "RTOS & Scheduling", "Hard",
    "In Priority Ceiling Protocol (PCP), each mutex is assigned a ceiling priority equal to the highest priority of any task that may lock it. When a task acquires a mutex, its priority is immediately raised to the ceiling. This prevents deadlocks (strict ordering) and bounds priority inversion to one blocking section. More predictable than Priority Inheritance but requires knowing all task priorities upfront."),

  // ═══════════════════════════════════════════════════════════════
  // DIGITAL LOGIC & CIRCUITS — EXPANDED (40 more)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What is a FIFO and how is it used in digital design?", "Digital Logic & Circuits", "Medium",
    "A FIFO (First In, First Out) is a buffer where data exits in the order it enters. In digital design, FIFOs decouple data producers from consumers, cross clock domains (async FIFO with Gray-coded pointers), buffer burst data, and match data rates. Key signals: write enable, read enable, full, empty, almost-full/empty flags."),
  makeQ("What are Karnaugh maps used for?", "Digital Logic & Circuits", "Easy",
    "Karnaugh maps (K-maps) are a graphical method to simplify Boolean expressions. You plot truth table outputs on a grid arranged so adjacent cells differ by one bit (Gray code order). Group adjacent 1s into power-of-2 rectangles to find minimized SOP (Sum of Products) expressions. Practical for up to 4-5 variables; larger designs use Quine-McCluskey or synthesis tools."),
  makeQ("What is the difference between combinational and sequential logic?", "Digital Logic & Circuits", "Easy",
    "Combinational logic: outputs depend only on current inputs (no memory). Examples: MUX, decoder, adder, ALU. Sequential logic: outputs depend on current inputs AND past state (has memory elements like flip-flops). Examples: counters, shift registers, state machines. Most digital systems combine both."),
  makeQ("What is a shift register and what are its applications?", "Digital Logic & Circuits", "Easy",
    "A shift register is a chain of flip-flops where data shifts one position per clock edge. Types: SISO, SIPO, PISO, PIPO. Applications: serial-to-parallel conversion (SPI), parallel-to-serial conversion, delay lines, pseudo-random number generators (LFSR), and LED display drivers (74HC595)."),
  makeQ("What is an LFSR and what is it used for?", "Digital Logic & Circuits", "Medium",
    "A Linear Feedback Shift Register uses XOR feedback from specific taps to generate pseudo-random bit sequences. With proper tap positions, an n-bit LFSR cycles through 2^n - 1 states before repeating. Uses: pseudo-random number generation, CRC calculation, scrambling/descrambling in communication, built-in self-test (BIST) for VLSI, and noise generation."),
  makeQ("What is a decoder and an encoder in digital logic?", "Digital Logic & Circuits", "Easy",
    "Decoder: converts n-bit input to 2^n output lines (only one active at a time). Example: 3-to-8 decoder for memory address selection. Encoder: inverse — converts 2^n input lines to n-bit output. Priority encoder handles multiple active inputs by encoding the highest-priority one. Used in interrupt controllers and address decoders."),
  makeQ("What is a tri-state buffer?", "Digital Logic & Circuits", "Easy",
    "A tri-state (three-state) buffer has three output states: high, low, and high-impedance (Hi-Z). The enable pin controls whether the buffer drives the output or disconnects it (Hi-Z). Used for: shared buses where multiple devices can drive the same line, bidirectional data buses, and memory interfaces. Only one device should drive the bus at a time."),
  makeQ("What is pipelining in digital design?", "Digital Logic & Circuits", "Hard",
    "Pipelining splits combinational logic into stages separated by registers. Each stage processes different data simultaneously, increasing throughput at the cost of latency and area. Example: a 4-stage pipeline processes 4 items concurrently. Maximum clock frequency is determined by the slowest pipeline stage. Used in CPUs, DSP blocks, and high-speed data paths."),
  makeQ("What is clock gating and why is it used?", "Digital Logic & Circuits", "Medium",
    "Clock gating disables the clock to inactive flip-flops to save dynamic power (since power ∝ switching activity). An AND/OR gate or integrated clock gating cell controls whether the clock reaches a register block. Widely used in low-power designs. Must be glitch-free to avoid false clocking. Synthesis tools can automatically insert clock gates."),
  makeQ("What is a ring oscillator?", "Digital Logic & Circuits", "Medium",
    "A ring oscillator is an odd number of inverters connected in a loop. The output oscillates because the feedback is always unstable (inverted). Frequency depends on the number of stages and gate delay: f = 1 / (2 * N * t_delay). Used for: on-chip frequency generation, process characterization, random number generation, and measuring gate delay."),
  makeQ("What is the difference between SRAM and DRAM?", "Digital Logic & Circuits", "Medium",
    "SRAM: uses 6 transistors per bit, fast, no refresh needed, used for caches and MCU RAM. DRAM: uses 1 transistor + 1 capacitor per bit, cheaper per bit, requires periodic refresh, used for main memory. SRAM is faster but more expensive per bit. Flash is non-volatile but slower and has limited write endurance."),
  makeQ("What is a phase-locked loop (PLL)?", "Digital Logic & Circuits", "Hard",
    "A PLL is a feedback system that generates an output clock synchronized (phase-locked) to a reference clock. Components: phase detector, loop filter, voltage-controlled oscillator (VCO), and optional frequency divider. Used for: clock multiplication (e.g., 8MHz crystal → 72MHz system clock on STM32), clock recovery from data streams, and frequency synthesis."),
  makeQ("What are hazards in combinational logic?", "Digital Logic & Circuits", "Medium",
    "Hazards are unwanted momentary output glitches caused by different propagation delays through logic paths. Static hazard: output should stay constant but briefly glitches. Dynamic hazard: output changes multiple times during a single transition. Eliminated by: adding consensus terms in SOP, using hazard-free logic, or registering outputs."),
  makeQ("What is a carry-lookahead adder?", "Digital Logic & Circuits", "Hard",
    "A carry-lookahead adder computes all carry bits simultaneously using generate (G=A·B) and propagate (P=A⊕B) signals, rather than waiting for carries to ripple through. This reduces addition delay from O(n) to O(log n). More complex than a ripple-carry adder but much faster. Used in ALUs and high-performance arithmetic units."),
  makeQ("What is the difference between Flash, EEPROM, and FRAM?", "Digital Logic & Circuits", "Medium",
    "Flash: block-erase then program, high density, limited write endurance (~10K-100K cycles), used for firmware. EEPROM: byte-erasable, lower density, higher endurance (~1M cycles), used for configuration data. FRAM: ferroelectric RAM, unlimited write endurance, fast writes, byte-addressable, retains data without power, more expensive. Choose based on write frequency and density needs."),
  makeQ("What is power consumption in CMOS circuits? Static vs dynamic.", "Digital Logic & Circuits", "Medium",
    "Dynamic power: P = α·C·V²·f (α = switching activity, C = capacitance, V = voltage, f = frequency). Dominates in active circuits. Reduce by: lowering voltage, frequency, or switching activity (clock gating). Static power: due to leakage current, significant in deep-sub-micron processes. Total power = dynamic + static + short-circuit."),
  makeQ("What is a bus arbiter?", "Digital Logic & Circuits", "Medium",
    "A bus arbiter controls access to a shared bus when multiple masters want to communicate simultaneously. Arbitration schemes: fixed priority (simple but can starve low-priority masters), round-robin (fair), time-division (each master gets a slot). On CAN bus, arbitration is built into the protocol using message IDs."),
  makeQ("What is a watchpoint vs a breakpoint in debugging?", "Digital Logic & Circuits", "Easy",
    "A breakpoint halts execution when a specific code address is reached (instruction fetch). A watchpoint (data breakpoint) halts when a specific memory address is read or written. Watchpoints are invaluable for finding who/what is corrupting a variable. ARM Cortex-M DWT (Data Watchpoint and Trace) unit supports hardware watchpoints."),

  // ═══════════════════════════════════════════════════════════════
  // COMMUNICATION PROTOCOLS — EXPANDED (50 more)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What is the I2C START and STOP condition?", "Communication Protocols", "Easy",
    "START: SDA transitions high-to-low while SCL is high. This signals the beginning of a transaction. STOP: SDA transitions low-to-high while SCL is high. This releases the bus. Between START and STOP, SDA only changes when SCL is low (normal data). A repeated START (Sr) starts a new transaction without releasing the bus."),
  makeQ("What is a NACK in I2C and what causes it?", "Communication Protocols", "Easy",
    "NACK (Not Acknowledge): the receiver pulls SDA high during the 9th clock pulse (ACK bit). Causes: no slave at the addressed address, slave busy/not ready, master reading last byte (signals end of read), or slave register doesn't exist. The master should handle NACKs by generating a STOP condition and optionally retrying."),
  makeQ("What is SPI chip select (CS) and how does it work?", "Communication Protocols", "Easy",
    "CS (Chip Select) / SS (Slave Select) is an active-low signal from master to slave. Pulling CS low selects a specific slave for communication. Each slave has its own CS line. When CS is high, the slave ignores SCK and MISO goes high-impedance. Some devices use CS rising edge to latch the transaction (end of frame)."),
  makeQ("What is UART flow control (RTS/CTS)?", "Communication Protocols", "Medium",
    "Hardware flow control uses two extra signals: RTS (Request To Send) and CTS (Clear To Send). The receiver deasserts CTS when its buffer is nearly full, telling the sender to pause. The sender checks CTS before transmitting. Prevents buffer overflow on slower receivers. Software flow control uses XON/XOFF characters but is less reliable."),
  makeQ("What is a UART framing error?", "Communication Protocols", "Easy",
    "A framing error occurs when the receiver doesn't see the expected stop bit (logic high) at the end of a frame. Causes: baud rate mismatch (most common), noise on the line, or the transmitter starting a new frame too early. Diagnosis: verify baud rates match, check signal quality with oscilloscope, and ensure proper voltage levels."),
  makeQ("What is the maximum speed of I2C in its different modes?", "Communication Protocols", "Easy",
    "Standard mode: 100 kbit/s. Fast mode: 400 kbit/s. Fast mode plus (Fm+): 1 Mbit/s. High-speed mode (Hs): 3.4 Mbit/s. Ultra-fast mode: 5 Mbit/s (unidirectional). Most embedded devices use Standard or Fast mode. Higher modes require specific hardware support and careful PCB design."),
  makeQ("How does CAN bus arbitration work?", "Communication Protocols", "Hard",
    "CAN uses non-destructive bitwise arbitration. All nodes start transmitting simultaneously. The arbitration field (message ID) is sent bit by bit. A node sending a recessive bit (1) that reads back a dominant bit (0) loses arbitration and stops transmitting. The node with the lowest ID (most 0s) wins. This happens naturally on the wired-AND bus without collision or data loss."),
  makeQ("What is a CAN bus error frame?", "Communication Protocols", "Hard",
    "An error frame is transmitted by any node that detects a bus error. It consists of an error flag (6 dominant bits — deliberately violating bit stuffing rules to alert all nodes) followed by an error delimiter. This causes all nodes to discard the corrupted frame. The transmitting node automatically retransmits. Nodes track error counters to transition between error-active, error-passive, and bus-off states."),
  makeQ("What is LIN bus and how does it differ from CAN?", "Communication Protocols", "Medium",
    "LIN (Local Interconnect Network) is a low-cost, single-wire, master-slave serial protocol for non-critical automotive subsystems. Single master, up to 16 slaves. Speed: up to 20 kbit/s. Much cheaper than CAN (single wire, no transceiver needed). Used for: window controls, mirror adjustment, seat positioning, rain sensors — where CAN's cost is unjustified."),
  makeQ("What is Ethernet and how does it differ from industrial Ethernet?", "Communication Protocols", "Medium",
    "Standard Ethernet (IEEE 802.3) is non-deterministic (CSMA/CD) — unsuitable for real-time control. Industrial Ethernet protocols add real-time guarantees: EtherCAT (on-the-fly processing), PROFINET (time-slotted), EtherNet/IP (CIP over TCP/UDP), and TSN (Time-Sensitive Networking). They achieve deterministic timing through special MAC layers, scheduling, or modified frame handling."),
  makeQ("What is the OSI model and how does it apply to embedded protocols?", "Communication Protocols", "Medium",
    "The OSI model has 7 layers: Physical, Data Link, Network, Transport, Session, Presentation, Application. UART/SPI/I2C operate at Physical + Data Link. CAN adds robust error handling at Data Link. TCP/IP maps to Network (IP) and Transport (TCP/UDP). Modbus is Application layer over serial (Physical) or TCP (Transport). Understanding layers helps design protocol stacks."),
  makeQ("What is a UART break condition?", "Communication Protocols", "Medium",
    "A break condition is when the TX line is held low (logic 0) for longer than a frame duration (start bit + data bits + stop bit). It violates normal framing and is detectable by the receiver. Used in: LIN bus (sync break to start a frame), DMX512 lighting protocol, and some bootloader protocols as an attention signal."),
  makeQ("What is bit stuffing in CAN?", "Communication Protocols", "Medium",
    "CAN uses bit stuffing to maintain synchronization: after 5 consecutive bits of the same polarity, a complementary stuff bit is inserted. The receiver removes stuff bits. This ensures enough edges on the bus for clock recovery. A violation of the bit stuffing rule (6 consecutive same bits) is used intentionally in error frames to signal errors."),
  makeQ("What is I2C bus capacitance and why does it matter?", "Communication Protocols", "Medium",
    "The I2C spec limits total bus capacitance to 400pF (standard mode). Each device, trace, and connector adds capacitance. High capacitance slows rise times (I2C uses open-drain with pull-up resistors), limiting maximum speed. Mitigation: stronger pull-ups (lower resistance), shorter traces, fewer devices, or use I2C bus buffers/repeaters."),
  makeQ("What is the difference between simplex, half-duplex, and full-duplex?", "Communication Protocols", "Easy",
    "Simplex: one-way only (e.g., sensor → MCU, radio broadcast). Half-duplex: bidirectional but one direction at a time (I2C, RS-485 2-wire, walkie-talkie). Full-duplex: both directions simultaneously (SPI, UART, RS-485 4-wire, Ethernet). Full-duplex provides higher throughput but requires more wires or bandwidth."),
  makeQ("What is MQTT and how is it used in IoT?", "Communication Protocols", "Medium",
    "MQTT (Message Queuing Telemetry Transport) is a lightweight publish-subscribe protocol for IoT. Clients publish messages to topics on a broker; subscribers receive messages for topics they've subscribed to. Features: QoS levels (0=at most once, 1=at least once, 2=exactly once), last will testament, retained messages. Low bandwidth, runs over TCP. Used for sensor data, device control, telemetry."),
  makeQ("What is CoAP and how does it compare to HTTP?", "Communication Protocols", "Hard",
    "CoAP (Constrained Application Protocol) is a lightweight RESTful protocol for IoT devices. Runs over UDP (vs HTTP over TCP), uses compact binary header (4 bytes vs HTTP's text headers), supports observe (push notifications), and has built-in content negotiation. Designed for low-power, lossy networks. Translatable to HTTP via proxies for cloud integration."),
  makeQ("What is a protocol buffer (protobuf) and when would you use it in embedded?", "Communication Protocols", "Hard",
    "Protocol Buffers (protobuf) is Google's binary serialization format. Messages are defined in .proto files and compiled to C code. Benefits over JSON: much smaller on the wire, faster parsing, strongly typed. In embedded: used for structured telemetry, configuration storage, and device-to-cloud communication. Nanopb is a popular lightweight C implementation for MCUs."),
  makeQ("What is 1-Wire protocol?", "Communication Protocols", "Medium",
    "1-Wire (by Dallas/Maxim) uses a single data line (plus ground) for communication and power. Each device has a unique 64-bit ROM ID. Master initiates communication with reset pulses. Devices are parasite-powered from the data line. Slow (~16.3 kbit/s) but minimal wiring. Used for: temperature sensors (DS18B20), iButtons, identification/authentication."),
  makeQ("What is the difference between big-endian and little-endian in protocol contexts?", "Communication Protocols", "Easy",
    "Network byte order (TCP/IP, CAN, I2C) is big-endian (MSB first). Many MCUs (ARM Cortex-M) are little-endian (LSB first). When sending multi-byte data over a network, you must convert: htonl/htons (host-to-network), ntohl/ntohs (network-to-host). Forgetting this conversion causes data corruption in protocol communication."),
  makeQ("What is BLE (Bluetooth Low Energy) and how does it differ from classic Bluetooth?", "Communication Protocols", "Medium",
    "BLE is optimized for low-power, intermittent data transfer. Much lower power than classic Bluetooth (months on coin cell). Simpler protocol stack, faster connection setup. Uses GATT profile with services and characteristics. Data rate: ~1 Mbps (BLE 4) to ~2 Mbps (BLE 5). Range: ~100m+ (BLE 5). Used in: wearables, sensors, beacons, medical devices. Not suitable for audio streaming (use classic BT)."),
  makeQ("What is LoRa/LoRaWAN?", "Communication Protocols", "Medium",
    "LoRa is a long-range, low-power radio modulation technique. LoRaWAN is the network protocol on top. Range: 2-15 km. Very low data rate (0.3-50 kbit/s). Excellent for: remote sensors, agriculture, smart cities, asset tracking. Uses chirp spread spectrum for noise immunity. Star-of-stars topology with gateways. Battery life: years on a single cell."),
  makeQ("What is Zigbee and where is it used?", "Communication Protocols", "Medium",
    "Zigbee is a mesh networking protocol based on IEEE 802.15.4. Low power, low data rate (~250 kbps), supports mesh topology (self-healing). Up to 65,000 nodes. Used in: smart home (lights, locks, thermostats), industrial sensor networks, building automation. Competes with BLE Mesh, Thread, and Z-Wave in the IoT space."),

  // ═══════════════════════════════════════════════════════════════
  // MICROCONTROLLERS — EXPANDED (50 more)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What is the ARM Cortex-M processor family hierarchy?", "Microcontrollers", "Medium",
    "Cortex-M0/M0+: smallest, lowest power, 2-stage pipeline, Thumb/Thumb-2 subset. Cortex-M3: full Thumb-2, hardware divide, bit-banding, 3-stage pipeline. Cortex-M4: M3 + DSP instructions + optional FPU (single precision). Cortex-M7: superscalar, 6-stage pipeline, double-precision FPU option, cache, highest performance. Cortex-M33: M4 features + TrustZone security."),
  makeQ("What is bit-banding on ARM Cortex-M3/M4?", "Microcontrollers", "Hard",
    "Bit-banding maps each bit in a memory region to a full 32-bit word in a separate 'alias' region. Writing 0 or 1 to the alias word atomically clears or sets the corresponding bit. This provides atomic bit manipulation without read-modify-write sequences or disabling interrupts. Available for 1MB of SRAM and 1MB of peripheral space."),
  makeQ("What is the SysTick timer on ARM Cortex-M?", "Microcontrollers", "Easy",
    "SysTick is a built-in 24-bit down-counting timer in all Cortex-M processors. It generates periodic interrupts used for RTOS tick, time delays, and system timing. Configured via SYST_RVR (reload value), SYST_CVR (current value), and SYST_CSR (control). Can use the processor clock or an external reference clock."),
  makeQ("What are the fault exceptions on ARM Cortex-M?", "Microcontrollers", "Hard",
    "HardFault: catches all faults (always enabled). MemManage: MPU violations, access to non-existent memory. BusFault: bus errors during data/instruction fetch. UsageFault: undefined instruction, unaligned access, division by zero. On Cortex-M0, only HardFault exists. On M3/M4, others can be enabled separately. Debug by reading fault status registers (CFSR, HFSR, MMFAR, BFAR)."),
  makeQ("What is the PendSV exception used for?", "Microcontrollers", "Hard",
    "PendSV (Pendable Service Call) is typically used by RTOS to trigger context switches. It's set to the lowest priority so it only executes after all other ISRs complete. The RTOS sets PendSV pending when a context switch is needed (e.g., after a tick interrupt unblocks a higher-priority task), and PendSV performs the actual stack swap."),
  makeQ("What is flash wait states and why do they matter?", "Microcontrollers", "Medium",
    "Flash memory is slower than the CPU. At high clock speeds, the CPU must wait for Flash to respond — these are wait states. Example: STM32 at 72MHz needs 2 wait states for Flash access. Mitigation: Flash accelerator/prefetch buffer, instruction cache, running time-critical code from RAM. More wait states reduce effective throughput."),
  makeQ("What is a timer capture/compare mode?", "Microcontrollers", "Medium",
    "Capture mode: the timer records its count value when an external event occurs (input pin edge). Used for: measuring pulse width, frequency, time between events. Compare mode: triggers an action (output toggle, interrupt, DMA) when the timer count matches a preset value. Used for: PWM generation, periodic interrupts, output timing."),
  makeQ("What is an input capture and how would you measure a pulse width?", "Microcontrollers", "Medium",
    "Configure a timer in input capture mode on a pin. Capture on rising edge → read timer value (T1). Then capture on falling edge → read timer value (T2). Pulse width = (T2 - T1) * timer_period. Handle timer overflow if the pulse is longer than one timer period. Used for: encoder reading, frequency measurement, IR remote decoding."),
  makeQ("How does a quadrature encoder interface work?", "Microcontrollers", "Medium",
    "A quadrature encoder outputs two square waves (A and B) 90° out of phase. By detecting which signal leads, you determine rotation direction. Counting edges gives position. Many MCUs have dedicated encoder mode in timers — the hardware counts up/down automatically. Used in: motor position feedback, rotary knobs, and CNC machines."),
  makeQ("What is RTC (Real-Time Clock) in an MCU?", "Microcontrollers", "Easy",
    "An RTC maintains accurate time (seconds, minutes, hours, date) even during low-power modes, powered by a battery backup (VBAT pin). Uses a 32.768 kHz crystal oscillator (2^15 Hz, easily divided to 1 Hz). Features: alarms, calendar, wake-up timer, tamper detection. Used for: timestamps, scheduled wake-up, data logging, and time-stamped events."),
  makeQ("What is a brown-out detector (BOD)/reset?", "Microcontrollers", "Easy",
    "A brown-out detector monitors the supply voltage and resets the MCU if it drops below a safe threshold. This prevents erratic behavior from operating at too-low voltage (Flash reads may fail, logic levels become unreliable). Configured with programmable threshold levels. Critical for: battery-powered devices, systems with noisy power supplies."),
  makeQ("What is the difference between Harvard and Von Neumann architecture?", "Microcontrollers", "Easy",
    "Von Neumann: single memory bus for both instructions and data. Simpler but creates a bottleneck. Harvard: separate buses for instructions and data — can fetch both simultaneously. Most MCUs use modified Harvard: separate instruction/data buses internally but unified address space externally. ARM Cortex-M uses modified Harvard."),
  makeQ("What is a HAL (Hardware Abstraction Layer)?", "Microcontrollers", "Easy",
    "A HAL provides a standardized API that abstracts hardware-specific register manipulation. Example: HAL_GPIO_WritePin() instead of directly writing to GPIOB->ODR. Benefits: portability across MCU families, faster development, cleaner code. Drawbacks: overhead, less control, may hide important details. STM32 HAL, NXP SDK, and TI DriverLib are popular examples."),
  makeQ("What is the Arm CMSIS standard?", "Microcontrollers", "Medium",
    "CMSIS (Cortex Microcontroller Software Interface Standard) provides: standardized header files for Cortex-M core registers, startup code templates, intrinsic functions for special instructions, RTOS API (CMSIS-RTOS2), DSP library, NN library, and a standard device abstraction. It enables portable code across different Cortex-M vendors."),
  makeQ("What is a bus matrix in an MCU?", "Microcontrollers", "Hard",
    "A bus matrix (AHB matrix) is an interconnect that allows multiple bus masters (CPU, DMA, Ethernet) to access multiple slaves (Flash, SRAM, peripherals) simultaneously, as long as they're accessing different slaves. Round-robin or fixed-priority arbitration when conflicts occur. Understanding the bus matrix helps optimize DMA/CPU concurrent access patterns."),
  makeQ("What is write-back vs write-through cache?", "Microcontrollers", "Hard",
    "Write-through: every write goes to both cache and main memory immediately. Simple, always coherent, but slower writes. Write-back: writes only update the cache; main memory is updated later when the cache line is evicted. Faster writes but requires careful coherency management (especially with DMA). Cortex-M7 has optional cache — DMA transfers need cache maintenance operations."),
  makeQ("What is the MPU on ARM Cortex-M and how do you configure it?", "Microcontrollers", "Hard",
    "The MPU (Memory Protection Unit) divides memory into regions with configurable access permissions (read/write/execute) and attributes (cacheable, bufferable, shareable). Used for: preventing stack overflow (no-access region at stack bottom), protecting RTOS kernel from user tasks, preventing execution from RAM (security), and DMA buffer cache management. Configure via MPU_RBAR and MPU_RASR registers."),
  makeQ("What is the difference between NOR Flash and NAND Flash?", "Microcontrollers", "Medium",
    "NOR Flash: random access, fast reads, byte-programmable, used for code execution (XIP — execute in place). Slower writes. Most MCU internal Flash is NOR-like. NAND Flash: block access, higher density, cheaper per bit, faster writes, but no XIP. Used for data storage (SD cards, SSDs, USB drives). Requires ECC and wear-leveling."),
  makeQ("What is the purpose of the Nested Vectored Interrupt Controller (NVIC)?", "Microcontrollers", "Medium",
    "The NVIC manages all interrupts on Cortex-M: enabling/disabling, priority assignment (8 levels typical, configurable), pending/active status, tail-chaining (fast back-to-back interrupt handling), and late-arriving (higher-priority interrupt preempts during stacking). Accessed via NVIC registers or CMSIS functions (NVIC_EnableIRQ, NVIC_SetPriority)."),
  makeQ("What is the vector table and how does it work?", "Microcontrollers", "Medium",
    "The vector table is an array of 32-bit addresses at the start of memory. Entry 0: initial stack pointer. Entry 1: reset handler address. Entries 2+: exception/interrupt handler addresses (NMI, HardFault, SysTick, peripheral IRQs). On interrupt, the CPU reads the corresponding address and jumps to that handler. The table can be relocated using the VTOR register."),

  // ═══════════════════════════════════════════════════════════════
  // PCB & HARDWARE DESIGN — EXPANDED (40 more)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What is the difference between an LDO and a voltage divider for power?", "PCB & Hardware Design", "Easy",
    "A voltage divider uses two resistors to produce a lower voltage but has no regulation — output varies with load current and is very inefficient (current always flows through dividers). An LDO actively regulates the output voltage regardless of load changes, providing stable power. Never use a voltage divider to power active circuits."),
  makeQ("What is via stitching and why is it done?", "PCB & Hardware Design", "Medium",
    "Via stitching places multiple vias connecting ground planes on different layers throughout the PCB. This provides low-impedance ground connections, reduces loop inductance, improves EMI shielding, and prevents resonances in ground planes. Commonly placed around board edges, between ground pours, and around high-speed signal areas."),
  makeQ("What is the difference between a ferrite bead and an inductor?", "PCB & Hardware Design", "Medium",
    "Both are inductive components, but ferrite beads are designed to have high impedance at high frequencies (absorbing noise as heat), while inductors are designed to store energy with low losses. Use ferrite beads for: power supply filtering, noise suppression on signal lines. Use inductors for: DC-DC converters, filters, and energy storage applications."),
  makeQ("What is thermal relief on a PCB?", "PCB & Hardware Design", "Easy",
    "Thermal relief is a pattern of spoke-like connections between a pad and a copper plane (instead of a solid connection). This reduces heat sinking during soldering — without it, the large copper plane absorbs so much heat that solder won't flow properly. Important for through-hole components on power/ground planes."),
  makeQ("What is impedance matching and why is it important?", "PCB & Hardware Design", "Hard",
    "Impedance matching ensures the source, transmission line, and load have the same characteristic impedance. Mismatches cause signal reflections that degrade signal quality. For a 50Ω system: trace impedance = 50Ω, source/load impedance = 50Ω. Matching techniques: series termination resistor at source, parallel termination at load, or AC termination. Critical for >50MHz signals."),
  makeQ("How do you calculate trace width for a given current?", "PCB & Hardware Design", "Medium",
    "Use IPC-2152 standard or online calculators. Key factors: current, acceptable temperature rise, copper weight (oz/ft²), and whether the trace is on an outer or inner layer. Rule of thumb: ~1A per 10mil (0.25mm) width for 1oz copper on outer layer with 10°C rise. Internal layers carry less due to reduced cooling. Power traces should be generously oversized."),
  makeQ("What is a Kelvin connection (4-wire sensing)?", "PCB & Hardware Design", "Medium",
    "A Kelvin connection uses separate pairs of wires for current carrying and voltage sensing, eliminating contact and wire resistance from the measurement. In PCB design, current sense resistors should have separate pads for the sense lines routed directly to the ADC. This gives accurate voltage readings across the shunt resistor."),
  makeQ("What is crosstalk and how do you minimize it?", "PCB & Hardware Design", "Hard",
    "Crosstalk is unwanted signal coupling between adjacent traces through electric (capacitive) and magnetic (inductive) fields. Minimize by: increasing trace spacing (3× trace width rule), using ground planes (return current stays under the signal trace), reducing parallel run length, routing sensitive signals on different layers with orthogonal crossing, and using differential pairs."),
  makeQ("What is a keepout area on a PCB?", "PCB & Hardware Design", "Easy",
    "A keepout area is a defined region where no components, traces, vias, or copper pours are allowed. Reasons: antenna clearance (BLE/WiFi needs ground-free area), mechanical clearance (connectors, mounting holes), high-voltage isolation, or thermal sensitivity. Defined in the PCB design tool and enforced by DRC (Design Rule Check)."),
  makeQ("What is DRC (Design Rule Check) in PCB design?", "PCB & Hardware Design", "Easy",
    "DRC automatically checks the PCB layout against manufacturing rules: minimum trace width, spacing, via sizes, drill sizes, clearance from board edge, solder mask expansion, etc. It also checks electrical rules: unconnected nets, short circuits, and antenna rules. Always run DRC before sending to fabrication. Fix all errors; review warnings."),
  makeQ("What is the purpose of a test point on a PCB?", "PCB & Hardware Design", "Easy",
    "Test points are exposed pads or loops added to the PCB specifically for probing during debug and testing. Place them on: power rails, clock signals, communication buses, reset lines, and key control signals. They enable oscilloscope/logic analyzer access and automated testing (bed-of-nails fixture). Essential for debugging prototypes and production testing."),
  makeQ("What is a TVS diode and when do you use one?", "PCB & Hardware Design", "Medium",
    "A TVS (Transient Voltage Suppressor) diode clamps voltage spikes by conducting heavily when voltage exceeds its breakdown threshold, diverting the spike to ground. Used for ESD protection on: USB ports, external connectors, GPIO pins, and any signal exposed to the outside world. Choose based on: working voltage, clamping voltage, and peak pulse current."),
  makeQ("What is the difference between a 2-layer and 4-layer PCB?", "PCB & Hardware Design", "Medium",
    "2-layer: top and bottom signal/power. Cheaper, simpler, but harder for complex designs — no dedicated ground/power planes, worse signal integrity and EMI. 4-layer: Signal-Ground-Power-Signal. Dedicated planes for better signal integrity, lower impedance power distribution, better EMI, and easier routing. 4-layer is strongly recommended for MCU designs above ~25MHz."),
  makeQ("What is a Schottky diode and when is it preferred over a regular diode?", "PCB & Hardware Design", "Medium",
    "A Schottky diode has a metal-semiconductor junction (vs PN junction). Lower forward voltage drop (~0.2-0.4V vs ~0.6-0.7V), faster switching speed, but higher leakage current. Used in: power supply rectification (higher efficiency), freewheeling diodes in switching regulators, reverse polarity protection, and high-frequency circuits."),

  // ═══════════════════════════════════════════════════════════════
  // AUTOMATION & PLC — EXPANDED (40 more)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What is a proximity sensor and what types are used in automation?", "Automation & PLC", "Easy",
    "A proximity sensor detects nearby objects without physical contact. Types: Inductive (detects metals, uses eddy currents), Capacitive (detects any material, measures capacitance change), Ultrasonic (measures sound reflection time), Photoelectric (uses light beam), and Magnetic (reed switch/Hall effect). Choose based on: target material, sensing distance, environment, and speed."),
  makeQ("What is the difference between a normally-open (NO) and normally-closed (NC) contact?", "Automation & PLC", "Easy",
    "NO (Normally Open): contact is open (no current flow) when not actuated; closes when activated. NC (Normally Closed): contact is closed (current flows) when not actuated; opens when activated. NC is used for safety circuits (emergency stop) — a broken wire or lost signal opens the circuit and stops the machine (fail-safe)."),
  makeQ("What is a VFD (Variable Frequency Drive)?", "Automation & PLC", "Medium",
    "A VFD controls AC motor speed by varying the frequency and voltage of power supplied. Input AC → rectified to DC → inverted back to AC at desired frequency. Motor speed is proportional to frequency: N = 120f/P (f=frequency, P=poles). Benefits: energy savings, soft start, precise speed control, reduced mechanical stress. Controlled by PLC via analog output or communication bus."),
  makeQ("What is a 4-20mA current loop and why is it used?", "Automation & PLC", "Easy",
    "4-20mA is an analog signaling standard: 4mA = minimum measurement (not 0, so you can detect a broken wire at 0mA), 20mA = maximum measurement. Advantages over voltage signals: immune to wire resistance/length, noise-resistant, can power the sensor (2-wire loop), and break detection (0mA = fault). Standard in industrial process control."),
  makeQ("What is a PLC scan time and what affects it?", "Automation & PLC", "Easy",
    "Scan time is the total time for one complete PLC cycle (input scan + program execution + output scan + housekeeping). Affected by: program size/complexity, number of I/O points, communication overhead, and CPU speed. Typical: 1-100ms. Long scan times can cause missed fast events. Monitor scan time and optimize critical rungs."),
  makeQ("What is an encoder vs a resolver?", "Automation & PLC", "Medium",
    "Encoder: digital position sensor — incremental (pulses per revolution) or absolute (unique code per position). Uses optical or magnetic sensing. Resolver: analog position sensor — a transformer whose output varies with shaft angle. More robust (no electronics on the shaft, works in harsh environments). Resolvers need RDC (resolver-to-digital converter) for digital systems."),
  makeQ("What is the difference between a contactor and a relay?", "Automation & PLC", "Easy",
    "Both are electrically-operated switches. Contactors are designed for high-power loads (motors, heaters — up to thousands of amps), have arc suppression, can handle millions of operations, and often have auxiliary contacts. Relays are for lighter loads (signals, small devices — up to ~10-20A), are simpler and cheaper. Use contactors for motor control; relays for signal switching."),
  makeQ("What is a safety relay and how is it different from a standard relay?", "Automation & PLC", "Medium",
    "A safety relay provides fail-safe operation through: redundant contacts (dual-channel), forced-guided contacts (if one set welds, the other is prevented from closing), self-monitoring circuitry, and certified safety ratings (SIL/PLd). Used in: emergency stop circuits, light curtain monitoring, and safety interlock systems. Standard relays lack these redundancy and monitoring features."),
  makeQ("What is a thermocouple and how does it work?", "Automation & PLC", "Medium",
    "A thermocouple generates a voltage proportional to the temperature difference between two junctions of dissimilar metals (Seebeck effect). Types: K (most common, -200 to 1250°C), J, T, E, N, S, R, B — each with different ranges and sensitivities. Requires cold-junction compensation (CJC). Simple, robust, wide range, but low accuracy (~1-2°C). Signal conditioning needed (amplification, linearization)."),
  makeQ("What is PROFIBUS and PROFINET?", "Automation & PLC", "Medium",
    "PROFIBUS: a fieldbus protocol (RS-485 based) for connecting PLCs to field devices. Two variants: DP (fast I/O) and PA (process automation, intrinsically safe). Up to 12 Mbit/s. PROFINET: the Ethernet-based successor — faster, more capable, supports real-time (RT) and isochronous real-time (IRT) communication. Both are widely used in Siemens PLC ecosystems."),
  makeQ("What is a function block in PLC programming?", "Automation & PLC", "Easy",
    "A function block is a reusable programming element with inputs, outputs, and internal state (retains values between calls). Examples: PID controller block, timer (TON, TOF, TP), counter (CTU, CTD), flip-flop. Unlike plain functions, function blocks have persistent memory — calling a timer FB accumulates elapsed time across scan cycles."),
  makeQ("What are TON, TOF, and TP timers in PLC programming?", "Automation & PLC", "Easy",
    "TON (Timer On-Delay): output turns ON after input has been ON for a set time. TOF (Timer Off-Delay): output turns OFF after input has been OFF for a set time. TP (Timer Pulse): generates a fixed-duration pulse when triggered. All are fundamental to sequencing, debouncing, and time-based control in PLC programs."),
  makeQ("What is a CTU and CTD counter in PLC programming?", "Automation & PLC", "Easy",
    "CTU (Counter Up): increments on each rising edge of the count input; output activates when count reaches preset value. CTD (Counter Down): decrements from preset; output activates at zero. CTUD combines both. Used for: counting parts on a conveyor, tracking inventory, controlling batch processes, and sequencing operations."),
  makeQ("What is fieldbus and why was it developed?", "Automation & PLC", "Medium",
    "Fieldbus is a family of industrial digital communication protocols that replaced traditional point-to-point 4-20mA analog wiring. Benefits: reduced wiring (multiple devices on one cable), bidirectional communication, diagnostics, remote configuration, and digital accuracy. Examples: PROFIBUS, Foundation Fieldbus, DeviceNet, Modbus RTU. Evolved further to Industrial Ethernet."),
  makeQ("What is interlocking in PLC programming?", "Automation & PLC", "Easy",
    "Interlocking prevents conflicting operations from occurring simultaneously. Example: a motor cannot run forward and reverse at the same time — the forward start rung includes an NC contact of the reverse output (and vice versa). Also used for: preventing pump run without flow switch, ensuring door closed before machine starts. Essential for safety and equipment protection."),

  // ═══════════════════════════════════════════════════════════════
  // SIGNAL PROCESSING — EXPANDED (30 more)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What is a digital filter and why use it instead of an analog filter?", "Signal Processing", "Easy",
    "A digital filter processes a sampled signal mathematically. Advantages over analog: perfect reproducibility, easy to modify (change coefficients), can implement complex responses impossible in analog, no component drift/temperature sensitivity, easy to implement adaptive/nonlinear behavior. Disadvantages: requires ADC, introduces latency, limited by sampling rate and processing power."),
  makeQ("What is a window function and when is it used?", "Signal Processing", "Medium",
    "A window function (Hamming, Hanning, Blackman, etc.) is applied to a finite-length signal before FFT to reduce spectral leakage. Without windowing, the rectangular truncation creates sidelobes in the frequency domain. Different windows trade off main lobe width (frequency resolution) vs sidelobe level (dynamic range). Hanning is a good general-purpose choice."),
  makeQ("What is the Z-transform?", "Signal Processing", "Hard",
    "The Z-transform converts a discrete-time signal x[n] to the complex frequency domain: X(z) = Σ x[n]z^(-n). It's the discrete-time equivalent of the Laplace transform. Used for: analyzing and designing digital filters, determining system stability (poles inside unit circle = stable), and computing transfer functions H(z) = Y(z)/X(z)."),
  makeQ("What is a Butterworth filter?", "Signal Processing", "Medium",
    "A Butterworth filter has a maximally flat magnitude response in the passband — no ripple. It sacrifices rolloff steepness for smoothness. Transfer function: |H(jω)|² = 1/(1 + (ω/ωc)^2n) where n is the order. Higher order = steeper rolloff but more phase distortion. Common choice when passband flatness is the priority."),
  makeQ("What is a Chebyshev filter?", "Signal Processing", "Medium",
    "Chebyshev Type I filters have steeper rolloff than Butterworth of the same order, but allow ripple in the passband. Type II filters are flat in the passband but have ripple in the stopband. The trade-off is between passband flatness and rolloff steepness. Used when you need sharper cutoff and can tolerate some passband ripple."),
  makeQ("What is decimation and interpolation?", "Signal Processing", "Medium",
    "Decimation: reducing the sampling rate by keeping every Nth sample (preceded by anti-aliasing low-pass filter). Interpolation: increasing the sampling rate by inserting zeros between samples and low-pass filtering (smoothing). Used for: sample rate conversion, reducing data rate for storage/transmission, and matching ADC/DAC rates to processing requirements."),
  makeQ("What is the Discrete Cosine Transform (DCT)?", "Signal Processing", "Hard",
    "The DCT transforms a signal into a sum of cosine functions at different frequencies. Unlike DFT, it uses only real numbers (no complex). Widely used in: JPEG image compression, MP3 audio compression, and video coding. Its energy compaction property (most signal energy in few low-frequency coefficients) makes it ideal for lossy compression."),
  makeQ("What is convolution and how does it relate to filtering?", "Signal Processing", "Medium",
    "Convolution is the mathematical operation y[n] = Σ x[k]·h[n-k] where h is the impulse response and x is the input. FIR filtering IS convolution of the input with the filter coefficients. In the frequency domain, convolution becomes multiplication: Y(z) = X(z)·H(z). Understanding this duality is fundamental to filter design."),
  makeQ("What is a Kalman filter?", "Signal Processing", "Hard",
    "A Kalman filter is an optimal recursive estimator that combines noisy measurements with a dynamic model to estimate system state. Predict step: estimate next state from model. Update step: correct with new measurement weighted by Kalman gain (based on relative uncertainties). Used in: GPS/IMU sensor fusion, robot localization, tracking, and any system with noisy sensors and known dynamics."),
  makeQ("What is total harmonic distortion (THD)?", "Signal Processing", "Medium",
    "THD measures how much a signal deviates from a pure sine wave by quantifying the power in harmonic frequencies relative to the fundamental. THD(%) = sqrt(V2² + V3² + ... + Vn²)/V1 × 100. Low THD = clean signal. Important in: power quality analysis, audio systems, and ADC/DAC characterization. Measured using FFT analysis."),
  makeQ("What is an IIR biquad filter section?", "Signal Processing", "Medium",
    "A biquad is a second-order IIR filter section with 2 zeros and 2 poles: H(z) = (b0 + b1·z⁻¹ + b2·z⁻²) / (1 + a1·z⁻¹ + a2·z⁻²). Higher-order filters are implemented as cascaded biquad sections for numerical stability. Direct Form I, Direct Form II, and transposed forms offer different trade-offs for fixed-point implementation."),
  makeQ("What is dithering in ADC?", "Signal Processing", "Hard",
    "Dithering adds a small amount of noise to the analog signal before ADC conversion. This randomizes quantization error, converting it from deterministic distortion into a flat noise floor. The result: lower distortion at the cost of slightly higher noise. Used in audio, measurement, and imaging where distortion-free quantization is important. The added noise can be shaped or subtracted."),
  makeQ("What is the difference between correlation and convolution?", "Signal Processing", "Medium",
    "Correlation: measures similarity between two signals as a function of time lag. Cross-correlation: r[n] = Σ x[k]·y[k+n]. Auto-correlation: signal with itself. Convolution: y[n] = Σ x[k]·h[n-k] — note one signal is time-reversed. Correlation is used for: pattern matching, synchronization, radar/sonar. Convolution is used for: filtering, system response calculation."),

  // ═══════════════════════════════════════════════════════════════
  // POWER ELECTRONICS — EXPANDED (25 more)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What is a flyback converter?", "Power Electronics", "Hard",
    "A flyback converter is an isolated DC-DC converter derived from a buck-boost topology. It uses a transformer (actually a coupled inductor) to transfer energy: switch ON → energy stored in transformer primary; switch OFF → energy transferred to secondary. Provides galvanic isolation between input and output. Common in: AC-DC adapters, multiple output supplies, and isolated power for communication interfaces."),
  makeQ("What is a charge pump?", "Power Electronics", "Medium",
    "A charge pump uses capacitors and switches (MOSFETs or diodes) to boost or invert voltage without inductors. Capacitors are alternately charged in parallel and discharged in series to multiply voltage. Simple, low-noise, small footprint, but limited current capability. Used for: RS-232 level shifting, gate drive supply, LED drivers, and low-power voltage doubling."),
  makeQ("What is soft-start in a power supply?", "Power Electronics", "Easy",
    "Soft-start gradually ramps up the output voltage or current at startup instead of instantly applying full voltage. This limits inrush current (which can trip breakers or stress components), reduces voltage overshoot, and prevents damage to downstream circuits. Implemented with an RC network or digitally via PWM duty cycle ramping."),
  makeQ("What is a current sense resistor (shunt)?", "Power Electronics", "Easy",
    "A current sense resistor is a low-value precision resistor placed in series with the current path. Voltage across it (V = I × R) is measured to determine current. Low resistance (1mΩ to 100mΩ) minimizes power loss. Placement: low-side (between load and ground — simple but no short-circuit detection) or high-side (between supply and load — more complex but detects shorts)."),
  makeQ("What is ripple voltage in a power supply?", "Power Electronics", "Easy",
    "Ripple is the residual AC voltage superimposed on the DC output of a power supply. Caused by: incomplete filtering of switched/rectified waveforms. Measured as peak-to-peak voltage or percentage of DC output. Reduced by: larger output capacitors (lower ESR), higher switching frequency, better LC filtering. Critical for: analog circuits, ADC reference, and noise-sensitive loads."),
  makeQ("What is the difference between isolated and non-isolated power supplies?", "Power Electronics", "Medium",
    "Isolated: input and output are galvanically separated (no direct electrical connection) using a transformer. Safety: prevents ground loops, meets safety standards for mains-connected devices. Examples: flyback, forward converter. Non-isolated: input and output share a common ground. Simpler, cheaper, higher efficiency. Examples: buck, boost, LDO. Choose based on safety requirements and ground referencing needs."),
  makeQ("What is deadtime in half-bridge/H-bridge circuits?", "Power Electronics", "Medium",
    "Deadtime is a brief period when both high-side and low-side switches are OFF during switching transitions. This prevents shoot-through — a condition where both switches are ON simultaneously, creating a short circuit from supply to ground (potentially destructive). Deadtime is typically 100ns-1µs, configured in the MCU timer or gate driver. Too much deadtime increases distortion."),
  makeQ("What is a half-bridge vs full-bridge (H-bridge)?", "Power Electronics", "Medium",
    "Half-bridge: two switches driving a load between the midpoint and ground/supply. Can drive the load in one polarity. Full-bridge (H-bridge): four switches allowing the load to be driven in both polarities. Used for: bidirectional motor control, class-D audio amplifiers, and full-bridge DC-DC converters. Control logic must prevent shoot-through in both topologies."),
  makeQ("What is power factor and power factor correction (PFC)?", "Power Electronics", "Hard",
    "Power factor = real power / apparent power (range 0-1). Low PF means current and voltage are out of phase (reactive loads) or current is distorted (nonlinear loads like rectifiers). PFC circuits shape input current to follow voltage waveform, improving PF toward 1. Active PFC uses a boost converter controlled by a PFC IC. Required by regulations (IEC 61000-3-2) for >75W equipment."),
  makeQ("What are the common causes of MOSFET failure?", "Power Electronics", "Medium",
    "1) Exceeding Vds (drain-source voltage breakdown). 2) Exceeding Vgs (gate oxide rupture). 3) Excessive current/temperature. 4) Shoot-through in half-bridge. 5) Avalanche breakdown from inductive loads. 6) ESD damage to the gate. 7) Parasitic BJT latchup. Prevention: proper gate drive, snubber circuits, deadtime, thermal management, and operating within SOA (Safe Operating Area)."),
  makeQ("What is thermal management in embedded systems?", "Power Electronics", "Medium",
    "Key concepts: junction temperature (Tj), thermal resistance (θJA = junction-to-ambient, θJC = junction-to-case), power dissipation (P = V×I or I²R). Tj = Ta + P × θJA. Cooling methods: heatsinks, thermal pads/paste, copper pours on PCB, forced air, and component derating. Design rule: keep Tj well below rated max (typically derate by 20°C minimum)."),

  // ═══════════════════════════════════════════════════════════════
  // SYSTEM DESIGN — EXPANDED (45 more)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What is a finite state machine (FSM) and how do you design one?", "System Design", "Medium",
    "An FSM has: defined states, transitions triggered by events/conditions, and actions performed on transitions or in states. Design steps: 1) List all states. 2) Define events/inputs. 3) Draw state transition diagram. 4) Define actions for each transition. 5) Implement as switch-case or table-driven code. Essential for: protocol handlers, UI flows, motor controllers, and device control sequences."),
  makeQ("How would you design a battery-powered sensor that lasts 5 years?", "System Design", "Hard",
    "Power budget: calculate average current. 5 years = 43,800 hours. CR2450 (620mAh) needs avg < 14µA. Strategies: sleep most of the time (wake every 15-60 min), use lowest-power MCU mode (nA sleep), duty-cycle radio (LoRa/BLE beacon), minimize wake time (DMA-driven sensor read), use efficient regulators (or direct battery connection), and choose low-quiescent-current components."),
  makeQ("What is FOTA/OTA and how do you make it reliable?", "System Design", "Hard",
    "FOTA (Firmware Over The Air) updates firmware remotely. Reliable design: A/B image slots (never overwrite running firmware), integrity verification (CRC-32 or SHA-256) before marking new image valid, rollback on boot failure (watchdog counts boot attempts), encrypted transfer (TLS), signed images (RSA/ECDSA), resume-capable download, and power-loss tolerance (atomic swap flag in NVM)."),
  makeQ("What is a watchdog window timer?", "System Design", "Medium",
    "A window watchdog requires feeding within a time window — not too early AND not too late. Feeding too early also triggers a reset. This catches: programs running too fast (unexpected code path), as well as programs that are stuck. More robust than a standard watchdog that only catches 'too late.' Available on many STM32 MCUs (WWDG)."),
  makeQ("How do you design a robust communication protocol between MCUs?", "System Design", "Hard",
    "Key elements: 1) Framing — start marker, length field, payload, checksum, end marker. 2) Error detection — CRC-16 or CRC-32. 3) Acknowledgment — receiver sends ACK/NACK. 4) Timeout and retry — handle lost messages. 5) Sequence numbers — detect duplicates and ordering. 6) Escape characters — handle data bytes that look like markers. Consider: byte-stuffing (SLIP/COBS), flow control, and graceful degradation."),
  makeQ("What is defensive programming in embedded systems?", "System Design", "Medium",
    "Techniques to handle unexpected conditions: validate all inputs (range checking, null pointer checks), use assert/static_assert, initialize all variables, handle all switch cases (default with error), check return values from all function calls, use timeouts on all blocking operations, implement watchdog timer, use CRC on stored/transmitted data, and test boundary conditions."),
  makeQ("What is the V-model in embedded software development?", "System Design", "Medium",
    "The V-model maps each development phase to a corresponding testing phase: Requirements ↔ Acceptance Testing, System Design ↔ System Testing, Architecture ↔ Integration Testing, Detailed Design ↔ Unit Testing. Implementation is at the bottom of the V. Each test level verifies its corresponding design level. Standard in automotive (ISO 26262) and safety-critical development."),
  makeQ("What is AUTOSAR and why is it important in automotive embedded?", "System Design", "Hard",
    "AUTOSAR (AUTomotive Open System ARchitecture) is a standardized software architecture for automotive ECUs. Layers: Application (SWCs), Runtime Environment (RTE), Basic Software (BSW — OS, communication, diagnostics, drivers). Benefits: software reuse across ECUs/vehicles, standard interfaces, vendor independence, and separation of application from hardware. Classic AUTOSAR for deterministic systems; Adaptive AUTOSAR for high-performance (ADAS)."),
  makeQ("What is ISO 26262 and what are ASILs?", "System Design", "Hard",
    "ISO 26262 is the functional safety standard for automotive. ASIL (Automotive Safety Integrity Level) ranges from A (lowest) to D (highest). Determined by: severity, probability of exposure, and controllability. ASIL D requires: highest code coverage, redundancy, formal methods. QM (Quality Management) = no safety requirement. Each safety goal is assigned an ASIL that drives development rigor."),
  makeQ("What is HIL (Hardware-in-the-Loop) testing?", "System Design", "Medium",
    "HIL testing connects the real ECU/controller to a simulator that emulates the physical system (plant, sensors, actuators). The ECU runs production firmware while the simulator generates realistic inputs and verifies outputs. Benefits: test dangerous/expensive scenarios safely, automate regression testing, test fault injection. Essential in automotive, aerospace, and industrial control development."),
  makeQ("What is SIL (Software-in-the-Loop) vs MIL (Model-in-the-Loop) testing?", "System Design", "Hard",
    "MIL: test the control algorithm model (e.g., Simulink) against the plant model. Pure simulation. SIL: compile the actual C code from the model and test against the plant model on a PC. PIL (Processor-in-the-Loop): run C code on the target processor against the plant model. HIL: target hardware against a real-time plant simulator. Each level adds realism and catches different issues."),
  makeQ("What is CRC and how do you implement it?", "System Design", "Easy",
    "CRC (Cyclic Redundancy Check) is an error-detecting code based on polynomial division. The data is treated as a binary polynomial and divided by a generator polynomial; the remainder is the CRC. Common: CRC-8, CRC-16, CRC-32. Implementation: bit-by-bit (simple but slow), table-driven (pre-compute remainders for each byte — fast, uses 256 entries), or hardware CRC peripheral on many MCUs."),
  makeQ("What is the difference between big-bang integration and incremental integration?", "System Design", "Medium",
    "Big-bang: integrate all modules at once and test. Simple but hard to isolate bugs. Incremental: add and test modules one at a time (top-down, bottom-up, or sandwich). Easier to find bugs since you know what changed. In embedded: start with hardware bring-up (clock, power, serial debug), then add peripherals one by one, testing each before moving on."),
  makeQ("What is a design pattern commonly used in embedded systems?", "System Design", "Medium",
    "Common patterns: State Machine (sequential behavior), Observer (event notification, publish-subscribe), Singleton (single instance for hardware resources), Command (encapsulate requests), Strategy (interchangeable algorithms), and Active Object (each task has its own event loop and queue). Also: double buffering, producer-consumer, and circular buffer. Patterns improve modularity and testability."),
  makeQ("How do you handle version management for firmware?", "System Design", "Medium",
    "Use semantic versioning (major.minor.patch) embedded in the firmware binary. Store version in a fixed Flash location or struct. Include in: boot log, device info response, OTA compatibility check. Track in Git with tags. For OTA: version must be checked before update (prevent downgrade attacks). Include hardware revision compatibility. Build system should auto-increment or embed Git hash."),
  makeQ("What is a memory map in embedded systems?", "System Design", "Easy",
    "A memory map defines the address ranges for different memory types and peripherals: Flash (code), SRAM (data), peripheral registers, system control, and external memory. On ARM Cortex-M: 0x00000000 = code, 0x20000000 = SRAM, 0x40000000 = peripherals, 0xE0000000 = system. Understanding the memory map is essential for: linker scripts, debugging, DMA configuration, and MPU setup."),
  makeQ("What is a bootloader's role in secure boot?", "System Design", "Hard",
    "Secure boot ensures only authenticated firmware runs. Process: 1) Boot ROM (immutable) verifies bootloader signature using a public key fused in OTP. 2) Bootloader verifies application image signature. 3) Chain of trust — each stage authenticates the next. Uses asymmetric crypto (RSA/ECDSA) for signatures, hash functions (SHA-256) for integrity. Prevents: tampered firmware, unauthorized code execution, and IP theft."),
  makeQ("What is code coverage and what types exist?", "System Design", "Medium",
    "Code coverage measures how much source code is exercised by tests. Types: Statement coverage (each line executed), Branch/Decision coverage (each if/else branch taken), MC/DC (Modified Condition/Decision Coverage — each condition independently affects the outcome). ISO 26262 ASIL D requires MC/DC. Tools: gcov, LDRA, VectorCAST. 100% statement coverage doesn't guarantee bug-free code."),

  // ═══════════════════════════════════════════════════════════════
  // BEHAVIORAL — EXPANDED (30 more)
  // ═══════════════════════════════════════════════════════════════
  makeQ("Tell me about a time you optimized embedded code for performance or memory.", "Behavioral", "Medium",
    "STAR format. Discuss: what was the constraint (Flash full, RAM overflow, timing not met). What profiling tools you used (logic analyzer, profiler, -fstack-usage). What specific optimizations (lookup tables, fixed-point math, DMA, algorithm change, compiler flags). Quantify results: 'reduced execution time by 40%' or 'saved 12KB of Flash.' Show systematic approach, not just guessing."),
  makeQ("Describe a time a project didn't go as planned. What did you learn?", "Behavioral", "Easy",
    "STAR format. Be honest about what went wrong (scope creep, underestimated complexity, hardware issue). Focus on: what you did about it (re-scoped, asked for help, changed approach), what you delivered despite the setback, and concrete lessons learned. Interviewers want to see: resilience, self-awareness, growth mindset, and accountability."),
  makeQ("How do you stay current with embedded systems technology?", "Behavioral", "Easy",
    "Discuss: read datasheets and app notes from chip vendors, follow blogs (Memfault Interrupt, Embedded Artistry, EEVBlog), participate in communities (Reddit r/embedded, EmbeddedRelated), attend conferences/webinars, personal projects with new MCUs/protocols, contribute to open-source (Zephyr, FreeRTOS), read books (Making Embedded Systems by Elecia White), and take online courses."),
  makeQ("How do you handle working with legacy code in embedded systems?", "Behavioral", "Medium",
    "STAR format. Key points: first understand before changing (read code, check git history, ask original authors), add tests around the area you're modifying, make small incremental changes with testing between each, document as you go, resist the urge to rewrite everything at once, and use static analysis to find hidden issues. Show patience and pragmatism."),
  makeQ("Describe your debugging methodology when faced with an intermittent bug.", "Behavioral", "Hard",
    "STAR format. Approach: 1) Gather data — when does it happen, how often, what conditions. 2) Form hypotheses — race condition, timing issue, power glitch, memory corruption. 3) Instrument — add logging, use logic analyzer, stress test. 4) Isolate — simplify the system until bug is reproducible. 5) Root cause — not just the symptom. 6) Fix and verify — confirm the bug is gone and understand why the fix works."),
  makeQ("Tell me about a time you mentored or helped a teammate learn something technical.", "Behavioral", "Easy",
    "STAR format. Describe: who needed help and what they were learning, how you approached teaching (pairing, documentation, code reviews, setting up exercises), what the outcome was (they became self-sufficient, delivered their task). Show: patience, communication skills, willingness to invest in others, and recognition that teaching deepens your own understanding."),
  makeQ("How do you decide when something is 'good enough' to ship?", "Behavioral", "Medium",
    "Discuss: define done criteria upfront (requirements met, tests pass, code reviewed, no critical bugs). Balance perfection vs deadlines — 80/20 rule. Differentiate must-haves from nice-to-haves. Use risk assessment — what's the cost of a bug in the field vs delay in shipping? In safety-critical: 'good enough' means meeting the safety standard, no shortcuts. In prototypes: iterate faster, fix later."),
  makeQ("Describe a time you had to work with incomplete or ambiguous requirements.", "Behavioral", "Medium",
    "STAR format. Show: how you identified the ambiguity, what steps you took to clarify (asked stakeholders, proposed alternatives, created prototypes), how you made progress despite uncertainty (iterative development, frequent check-ins), and what the outcome was. Demonstrate: proactive communication, assumption documentation, and comfort with ambiguity."),
  makeQ("What's a personal embedded project you're proud of?", "Behavioral", "Easy",
    "Pick a project that shows passion and technical depth. Describe: what you built and why, what technologies you chose (MCU, sensors, protocols, tools), the biggest challenge and how you overcame it, and what you learned. Show: initiative (self-driven, not just coursework), curiosity, and the ability to see a project through from idea to working prototype."),
  makeQ("How do you handle a disagreement about code quality with a reviewer?", "Behavioral", "Medium",
    "Discuss: listen and understand their perspective, separate style preferences from correctness issues, use data/standards to support your position (MISRA rule, performance measurements, maintainability argument), be willing to compromise on style but not on safety, and escalate to team lead if fundamentally stuck. Show: professionalism, open-mindedness, and focus on the best outcome for the project."),
  makeQ("Tell me about a time you had to debug a hardware-software interface issue.", "Behavioral", "Hard",
    "STAR format. Describe: the symptom, how you isolated whether it was hardware or software (oscilloscope, logic analyzer, test firmware), the root cause (wrong pin configuration, timing violation, electrical noise, incorrect register settings), the fix, and how you prevented recurrence. Show: systematic debugging, comfort with hardware tools, and collaboration with hardware engineers."),
  makeQ("How do you approach learning a new microcontroller platform?", "Behavioral", "Easy",
    "Steps: 1) Read the datasheet/reference manual overview. 2) Get a development board and blink an LED. 3) Set up the toolchain (IDE, compiler, debugger). 4) Exercise peripherals one by one (GPIO, UART, timer, ADC). 5) Port a small project from a familiar platform. 6) Explore vendor HAL vs register-level programming. Show: structured learning, hands-on approach, and comfort with datasheets."),
  makeQ("Describe a time you improved the reliability of an embedded system.", "Behavioral", "Medium",
    "STAR format. Examples: added watchdog timer to recover from hangs, implemented CRC checking on stored data, added brown-out detection, fixed race conditions with proper synchronization, added self-test at startup, implemented redundant sensor readings, or added graceful degradation for sensor failures. Quantify: 'reduced field failures from X to Y' if possible."),
  makeQ("What do you consider the most important quality in an embedded engineer?", "Behavioral", "Easy",
    "Good answers: attention to detail (bugs in embedded can be dangerous), systematic debugging skills (you can't just print-debug everything), understanding of hardware-software interaction (you need to read schematics and datasheets), patience (embedded bugs can be deeply hidden), and curiosity (the field is always evolving). Support with a personal example."),
  makeQ("How do you estimate how long an embedded project will take?", "Behavioral", "Medium",
    "Approach: break into sub-tasks, estimate each, add contingency (hardware bring-up always takes longer than expected), account for: PCB revision time, vendor lead times, debugging time (often 40-60% of total), testing and documentation. Use historical data from similar projects. Communicate ranges (optimistic/pessimistic) and update estimates as you learn more. Always buffer for unknowns."),

  // ═══════════════════════════════════════════════════════════════
  // EMBEDDED LINUX (NEW CATEGORY mapped to System Design)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What is the difference between bare-metal and embedded Linux?", "System Design", "Medium",
    "Bare-metal: your code runs directly on hardware with no OS. Full control, deterministic timing, minimal overhead, but you write all drivers and manage everything. Embedded Linux: full OS with kernel, drivers, file system, networking stack, process isolation. More complex, higher resource requirements (32+ MB RAM), but faster development for complex applications. Choose based on: real-time needs, complexity, and available resources."),
  makeQ("What is a BSP (Board Support Package)?", "System Design", "Medium",
    "A BSP provides all software needed to boot and run an OS on specific hardware: bootloader (U-Boot), kernel config and device tree, device drivers for board-specific hardware, root filesystem with essential tools, and cross-compilation toolchain. Typically provided by board/SoC vendors. BSP bring-up is one of the first tasks in an embedded Linux project."),
  makeQ("What is a device tree in embedded Linux?", "System Design", "Hard",
    "A device tree (.dts/.dtb) is a data structure describing hardware to the Linux kernel — what peripherals exist, their addresses, interrupts, and configuration. This replaces hard-coded board files, making the same kernel binary work on different boards with different device trees. Compiled from .dts (source) to .dtb (binary blob) and loaded by the bootloader."),
  makeQ("What is the difference between a kernel module and a built-in driver?", "System Design", "Medium",
    "Built-in: compiled into the kernel image, loaded at boot, always present, increases kernel size. Module (.ko): compiled separately, loaded/unloaded at runtime (insmod/rmmod), saves memory when not needed. Modules can't be used for drivers needed during boot (root filesystem driver). Most drivers are modules for flexibility. Use built-in for essential boot-time hardware."),
  makeQ("What is cross-compilation in embedded development?", "System Design", "Easy",
    "Cross-compilation means compiling code on one architecture (host, e.g., x86 PC) for a different architecture (target, e.g., ARM MCU). Required because embedded targets usually can't compile their own code (too slow, not enough resources). Uses a cross-toolchain: arm-none-eabi-gcc for bare-metal ARM, arm-linux-gnueabihf-gcc for Linux ARM. Set up via SDK, buildroot, or Yocto."),
  makeQ("What is U-Boot and what role does it play?", "System Design", "Medium",
    "U-Boot (Universal Boot Loader) is the most popular bootloader for embedded Linux. It initializes hardware (DRAM, clocks), provides a command-line for debugging, loads the kernel and device tree from Flash/SD/network into RAM, passes boot arguments to the kernel, and supports firmware updates. It bridges the gap between power-on and Linux kernel execution."),

  // ═══════════════════════════════════════════════════════════════
  // TESTING & QUALITY (mapped to System Design)
  // ═══════════════════════════════════════════════════════════════
  makeQ("What is unit testing in embedded systems and how do you do it?", "System Design", "Medium",
    "Unit testing tests individual functions/modules in isolation. In embedded: run tests on the host PC (not the target) using frameworks like Unity, CUnit, or Google Test. Mock/stub hardware dependencies (HAL functions, registers). Benefits: fast feedback, test edge cases, regression detection. Challenges: hardware-dependent code needs abstraction layers to be testable."),
  makeQ("What is static analysis and which tools are used in embedded?", "System Design", "Medium",
    "Static analysis examines code without executing it to find: potential bugs, undefined behavior, MISRA violations, security vulnerabilities, and dead code. Tools: PC-lint/FlexeLint, cppcheck, Coverity, Polyspace, PVS-Studio, and Clang Static Analyzer. Many find bugs that testing misses (uninitialized variables, buffer overflows, race conditions). Essential for safety-critical code."),
  makeQ("What is fuzz testing and can it be applied to embedded systems?", "System Design", "Hard",
    "Fuzz testing feeds random/mutated inputs to software to find crashes, hangs, and vulnerabilities. For embedded: fuzz communication protocol parsers, file parsers, and command handlers on the host PC (compiled with address sanitizer). Tools: AFL, libFuzzer. Effective at finding: buffer overflows, integer overflows, and unhandled edge cases in input processing code."),
  makeQ("What is regression testing?", "System Design", "Easy",
    "Regression testing re-runs existing tests after code changes to ensure nothing previously working is broken. In embedded: automated unit tests (CI pipeline), integration tests on target hardware (automated test bench), and manual smoke tests for UI/user interaction. Maintain a test suite that grows with features. Automate as much as possible — manual regression testing doesn't scale."),
];
